def balance_ab_ba(t, test_cases):
    results = []
    for s in test_cases:
        countAB = 0
        countBA = 0
        n = len(s)

        # Count occurrences of "ab" and "ba"
        for i in range(n - 1):
            if s[i] == 'a' and s[i + 1] == 'b':
                countAB += 1
            elif s[i] == 'b' and s[i + 1] == 'a':
                countBA += 1

        # If counts are already equal, no change is needed
        if countAB == countBA:
            results.append(s)
        else:
            # We need to make a change to balance the counts
            s_list = list(s)  # Convert string to list for easier manipulation
            # Change the last character to balance the counts
            if countAB > countBA:
                # Change the last character to 'a' if it's 'b'
                if s_list[-1] == 'b':
                    s_list[-1] = 'a'
                else:
                    s_list[-2] = 'b'
            else:
                # Change the last character to 'b' if it's 'a'
                if s_list[-1] == 'a':
                    s_list[-1] = 'b'
                else:
                    s_list[-2] = 'a'

            results.append(''.join(s_list))

    return results

