def compare_numbers(t, test_cases):
    results = []
    for i in range(t):
        x1, p1 = test_cases[i * 2]
        x2, p2 = test_cases[i * 2 + 1]

        # Calculate the effective length of both numbers
        len1 = len(str(x1)) + p1
        len2 = len(str(x2)) + p2

        if len1 > len2:
            results.append('>')
        elif len1 < len2:
            results.append('<')
        else:
            # Normalize the numbers by adjusting the number of zeros
            if p1 > p2:
                x2 *= 10 ** (p1 - p2)
            elif p2 > p1:
                x1 *= 10 ** (p2 - p1)

            # Compare the adjusted base integers
            if x1 > x2:
                results.append('>')
            elif x1 < x2:
                results.append('<')
            else:
                results.append('=')

    return results

